"use client";

/**
 * Empty / first-run dashboard (zero-data state) — cold build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Goal: show how the library behaves the moment a user signs up and has NO data.
 * Every metric is "—"/0, every chart receives empty or all-zero data, and the
 * primary surfaces are onboarding (Progress / ProgressWidget) + EmptyState +
 * StatusScreen.
 *
 * Discovery notes (docs-first; package source consulted only where docs were silent):
 *  - Charts: BarChart takes `data: ChartDataPoint[]`, DonutChart takes
 *    `segments: ChartDataPoint[]`, SparklineChart takes
 *    `data: Array<ChartDataPoint | number>`. The gunjo.jp docs say NOTHING about
 *    empty/zero behavior, so I read the source: all three guard div-by-zero
 *    (`Math.max(..., 1)`, `span = max - min || 1`, `normalizeChartValue` returns
 *    0 when `max <= 0`). DonutChart's conic gradient even has an explicit
 *    all-zero fallback to a solid muted ring. => empty/zero charts are SAFE.
 *  - Statistic: `{ label, value, change?, trend?, tone?, hint? }`. `value` is a
 *    ReactNode, so "—" renders fine. There is no built-in "no data" treatment;
 *    I express it with a muted value + hint.
 *  - Progress renders role=progressbar + aria-valuemin/max/now (verified in
 *    source; docs didn't mention it). ProgressWidget wraps Progress in a Card
 *    and clamps value to [0, max].
 *  - EmptyState / StatusScreen render their title as a <p>, NOT a heading
 *    element. Recorded as an a11y finding.
 *  - Icons come from lucide-react (a dependency of @gunjo/ui, hoisted to the
 *    app's node_modules).
 */

import * as React from "react";
import {
  Banner,
  BarChart,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  DonutChart,
  EmptyState,
  Progress,
  ProgressWidget,
  Separator,
  SparklineChart,
  Statistic,
  StatusScreen,
} from "@gunjo/ui";
import {
  Activity,
  ArrowRight,
  BarChart3,
  Bell,
  CheckCircle2,
  Circle,
  CreditCard,
  FolderPlus,
  Inbox,
  Rocket,
  Sparkles,
  Users,
} from "lucide-react";

/* ------------------------------------------------------------------ */
/* Onboarding checklist (the one real interaction)                     */
/* ------------------------------------------------------------------ */

interface Step {
  id: string;
  title: string;
  description: string;
  cta: string;
  icon: React.ReactNode;
}

const STEPS: Step[] = [
  {
    id: "profile",
    title: "プロフィールを完成させる",
    description: "名前とアバターを設定すると、メンバーが認識しやすくなります。",
    cta: "プロフィールを編集",
    icon: <Users className="h-4 w-4" />,
  },
  {
    id: "project",
    title: "最初のプロジェクトを作成",
    description: "プロジェクトは、データとダッシュボードを管理する場所です。",
    cta: "新規プロジェクト",
    icon: <FolderPlus className="h-4 w-4" />,
  },
  {
    id: "invite",
    title: "チームを招待する",
    description: "メンバーを招待すると、アクティビティが活発になります。",
    cta: "メンバーを招待",
    icon: <Sparkles className="h-4 w-4" />,
  },
  {
    id: "billing",
    title: "お支払い方法を追加",
    description: "任意 — 無料トライアル終了前までに設定すれば大丈夫です。",
    cta: "カードを追加",
    icon: <CreditCard className="h-4 w-4" />,
  },
];

function OnboardingChecklist() {
  // Start with the "profile" step pre-completed (1 of 4) — a realistic first run.
  const [done, setDone] = React.useState<Record<string, boolean>>({
    profile: true,
  });

  const completedCount = STEPS.filter((s) => done[s.id]).length;
  const allDone = completedCount === STEPS.length;

  const toggle = (id: string) =>
    setDone((prev) => ({ ...prev, [id]: !prev[id] }));

  return (
    <Card>
      <CardHeader>
        <div className="flex flex-wrap items-center justify-between gap-2">
          <CardTitle>はじめに</CardTitle>
          {/* Badge has no semantic "success" tone (only default/secondary/
              outline/destructive), so the all-done state uses the high-
              contrast `default` rather than a green. Recorded as a finding. */}
          <Badge variant={allDone ? "default" : "secondary"}>
            {STEPS.length} 件中 {completedCount} 件完了
          </Badge>
        </div>
        <CardDescription>
          これらのステップを完了して、ワークスペースを活用しましょう。
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-5">
        <div className="space-y-2">
          <Progress
            value={completedCount}
            max={STEPS.length}
            aria-label={`セットアップの進捗: ${STEPS.length} 件中 ${completedCount} 件完了`}
          />
          <p className="text-xs text-muted-foreground">
            {allDone
              ? "すべて完了 — ワークスペースの準備が整いました。"
              : `残り ${STEPS.length - completedCount} 件のステップ。`}
          </p>
        </div>

        <Separator />

        <ul className="space-y-3">
          {STEPS.map((step) => {
            const isDone = !!done[step.id];
            return (
              <li
                key={step.id}
                className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between"
              >
                <div className="flex min-w-0 items-start gap-3">
                  <button
                    type="button"
                    onClick={() => toggle(step.id)}
                    aria-pressed={isDone}
                    aria-label={
                      isDone
                        ? `「${step.title}」を未完了にする`
                        : `「${step.title}」を完了にする`
                    }
                    className="mt-0.5 shrink-0 rounded-full text-muted-foreground transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background"
                  >
                    {isDone ? (
                      <CheckCircle2 className="h-5 w-5 text-success" />
                    ) : (
                      <Circle className="h-5 w-5" />
                    )}
                  </button>
                  <div className="min-w-0">
                    <p
                      className={
                        "text-sm font-medium " +
                        (isDone
                          ? "text-muted-foreground line-through"
                          : "text-foreground")
                      }
                    >
                      {step.title}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {step.description}
                    </p>
                  </div>
                </div>
                <div className="shrink-0 pl-8 sm:pl-0">
                  <Button
                    variant={isDone ? "ghost" : "outline"}
                    size="sm"
                    onClick={() => toggle(step.id)}
                  >
                    {step.icon}
                    {isDone ? "完了" : step.cta}
                  </Button>
                </div>
              </li>
            );
          })}
        </ul>
      </CardContent>
    </Card>
  );
}

/* ------------------------------------------------------------------ */
/* Zero-data stat cards                                                 */
/* ------------------------------------------------------------------ */

const ZERO_STATS: Array<{ label: string; value: string; hint: string }> = [
  { label: "総売上", value: "—", hint: "取引はまだありません" },
  { label: "アクティブユーザー", value: "0", hint: "まずはチームを招待しましょう" },
  { label: "プロジェクト", value: "0", hint: "最初のプロジェクトを作成しましょう" },
  { label: "コンバージョン率", value: "—", hint: "算出にはデータが必要です" },
];

function ZeroStats() {
  return (
    <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
      {ZERO_STATS.map((s) => (
        <Statistic
          key={s.label}
          label={s.label}
          value={<span className="text-muted-foreground">{s.value}</span>}
          hint={s.hint}
        />
      ))}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Empty chart cards — the critical "chart with no data" probe          */
/* ------------------------------------------------------------------ */

function EmptyChartCard({
  title,
  description,
  icon,
  children,
}: {
  title: string;
  description: string;
  icon: React.ReactNode;
  children: React.ReactNode;
}) {
  return (
    <Card>
      <CardHeader>
        <div className="flex items-center gap-2">
          <span className="text-muted-foreground">{icon}</span>
          <CardTitle className="text-sm font-medium">{title}</CardTitle>
        </div>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent>
        {/* The chart renders (no crash) behind a "no data yet" overlay so the
            empty axis/ring reads as intentional rather than broken. */}
        <div className="relative">
          <div aria-hidden="true" className="opacity-40">
            {children}
          </div>
          <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
            <span className="rounded-full bg-muted px-3 py-1 text-xs font-medium text-muted-foreground">
              データはまだありません
            </span>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function EmptyCharts() {
  return (
    <div className="grid grid-cols-1 gap-4 lg:grid-cols-3">
      <EmptyChartCard
        title="月別売上"
        description="取引を記録すると、棒グラフが表示されます。"
        icon={<BarChart3 className="h-4 w-4" />}
      >
        {/* All-zero data: bars render at 0% height, axis + grid intact. */}
        <BarChart
          data={[
            { label: "1月", value: 0 },
            { label: "2月", value: 0 },
            { label: "3月", value: 0 },
            { label: "4月", value: 0 },
            { label: "5月", value: 0 },
            { label: "6月", value: 0 },
          ]}
        />
      </EmptyChartCard>

      <EmptyChartCard
        title="アクセス推移"
        description="訪問者の推移がここに表示されます。"
        icon={<Activity className="h-4 w-4" />}
      >
        {/* Truly empty array: renders an empty <polyline>, no NaN. */}
        <div className="flex h-[192px] items-center">
          <SparklineChart data={[]} />
        </div>
      </EmptyChartCard>

      <EmptyChartCard
        title="プラン使用量"
        description="ご利用が増えると、内訳がここに表示されます。"
        icon={<Inbox className="h-4 w-4" />}
      >
        {/* All-zero segments: solid muted ring fallback (no crash, no NaN). */}
        <DonutChart
          segments={[
            { label: "使用済み", value: 0 },
            { label: "残り", value: 0 },
          ]}
          centerValue={<span className="text-muted-foreground">0%</span>}
          centerLabel="使用中"
        />
      </EmptyChartCard>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Page                                                                 */
/* ------------------------------------------------------------------ */

export default function DashboardEmptyPage() {
  const [bannerOpen, setBannerOpen] = React.useState(true);
  const [showFullEmpty, setShowFullEmpty] = React.useState(false);

  if (showFullEmpty) {
    // Optional full-page StatusScreen variant: "No projects yet".
    return (
      <main className="flex flex-1 flex-col">
        <StatusScreen
          variant="coming-soon"
          icon={<Rocket className="h-16 w-16" />}
          title="プロジェクトがありません"
          description="最初のプロジェクトを作成すると、ダッシュボード・グラフ・アクティビティが使えるようになります。"
          action={
            <div className="flex flex-wrap items-center justify-center gap-2">
              <Button onClick={() => setShowFullEmpty(false)}>
                <FolderPlus className="h-4 w-4" />
                プロジェクトを作成
              </Button>
              <Button variant="outline" onClick={() => setShowFullEmpty(false)}>
                ダッシュボードに戻る
              </Button>
            </div>
          }
        />
      </main>
    );
  }

  return (
    <main className="flex-1 bg-background py-8">
      <Container size="2xl" className="space-y-8 px-4">
        {/* Welcome header */}
        <header className="space-y-1">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h1 className="text-2xl font-bold tracking-tight text-foreground">
                ようこそ Acme へ、ケイさん 👋
              </h1>
              <p className="text-sm text-muted-foreground">
                ワークスペースの準備が整いました。さっそく最初のデータを記録していきましょう。
              </p>
            </div>
            <Button variant="outline" onClick={() => setShowFullEmpty(true)}>
              <BarChart3 className="h-4 w-4" />
              空プロジェクト画面を見る
            </Button>
          </div>
        </header>

        {/* Get-started banner */}
        {bannerOpen ? (
          <Banner
            variant="info"
            icon={<Rocket className="h-4 w-4" />}
            action={
              <Button size="sm" variant="secondary">
                ツアーを開始
              </Button>
            }
            onDismiss={() => setBannerOpen(false)}
            dismissLabel="はじめにバナーを閉じる"
          >
            セットアップは完了です。いくつかの簡単なステップを進めて、ダッシュボードを充実させましょう。
          </Banner>
        ) : null}

        {/* Zero-data KPIs */}
        <section aria-labelledby="kpis-heading" className="space-y-3">
          <h2
            id="kpis-heading"
            className="text-sm font-semibold text-foreground"
          >
            概要
          </h2>
          <ZeroStats />
        </section>

        {/* Onboarding + a ProgressWidget side by side */}
        <section
          aria-labelledby="onboarding-heading"
          className="grid grid-cols-1 gap-4 lg:grid-cols-[2fr_1fr]"
        >
          <h2 id="onboarding-heading" className="sr-only">
            セットアップ
          </h2>
          <OnboardingChecklist />
          <div className="space-y-4">
            <ProgressWidget
              title="セットアップの進捗"
              value={1}
              max={4}
              label="25%"
              subtext="4 件中 1 件完了"
              icon={<Sparkles className="h-4 w-4" />}
            />
            <ProgressWidget
              title="トライアル"
              value={14}
              max={14}
              label="残り14日"
              subtext="カードの登録はまだ不要です"
              icon={<CreditCard className="h-4 w-4" />}
            />
          </div>
        </section>

        {/* Empty charts */}
        <section aria-labelledby="charts-heading" className="space-y-3">
          <h2
            id="charts-heading"
            className="text-sm font-semibold text-foreground"
          >
            分析
          </h2>
          <EmptyCharts />
        </section>

        {/* Empty activity feed */}
        <section aria-labelledby="activity-heading" className="space-y-3">
          <h2
            id="activity-heading"
            className="text-sm font-semibold text-foreground"
          >
            最近のアクティビティ
          </h2>
          <Card>
            <CardContent className="p-0">
              <EmptyState
                icon={<Bell className="h-6 w-6" />}
                title="アクティビティはまだありません"
                description="プロジェクトを作成したりメンバーを招待したりすると、その操作がここに表示されます。"
                action={
                  <Button>
                    <FolderPlus className="h-4 w-4" />
                    最初のプロジェクトを作成
                  </Button>
                }
              />
            </CardContent>
          </Card>
        </section>
      </Container>
    </main>
  );
}
